### 2.2 安全漏洞详情

#### SEC-001: 缺少超时控制（严重）

**问题代码** (`base-agent.ts:177-209`):
```typescript
async executeAndCollect(prompt: string, timeoutMs: number = 300000): Promise<string> {
  // ✅ 已有超时实现，但默认 5 分钟过长
  const timeoutPromise = new Promise<never>((_, reject) => {
    setTimeout(() => {
      reject(new Error(`Agent execution timeout after ${timeoutMs / 1000}s`));
    }, timeoutMs);
  });

  return await Promise.race([executionPromise(), timeoutPromise]);
}
```

**安全风险**:
- 默认 5 分钟超时过长，可能导致资源耗尽
- 没有最大重试次数限制
- 超时后未正确清理资源

**修复建议**:
```typescript
// 1. 缩短默认超时时间
async executeAndCollect(prompt: string, timeoutMs: number = 60000): Promise<string> {
  // 默认 1 分钟，而不是 5 分钟
}

// 2. 添加取消令牌
private abortController: AbortController | null = null;

async executeAndCollect(prompt: string, timeoutMs: number = 60000): Promise<string> {
  this.abortController = new AbortController();

  const timeoutPromise = new Promise<never>((_, reject) => {
    const timeoutId = setTimeout(() => {
      this.abortController?.abort();
      reject(new Error(`Agent execution timeout after ${timeoutMs / 1000}s`));
    }, timeoutMs);

    // 清理定时器
    this.abortController.signal.addEventListener('abort', () => {
      clearTimeout(timeoutId);
    });
  });

  // ... 执行逻辑
}

// 3. 添加取消方法
cancel(): void {
  this.abortController?.abort();
  this.conversationHistory = [];
}
```

