#### SEC-002: 敏感信息泄露（严重）

**问题代码** (`auto-iteration.ts:303-324`):
```typescript
private async sendNotification(info: { commitId: string; files: number; lines: number }): Promise<void> {
  try {
    const message = `✅ 新提交: ${info.commitId} (${info.files}个文件, +${info.lines}行)`;
    // ⚠️ 直接写入文件，可能包含敏感信息
    const notifyFile = '/tmp/ai-dev-notify.txt';
    fs.writeFileSync(notifyFile, JSON.stringify({
      message,
      timestamp: new Date().toISOString()
    }));
  }
}
```

**安全风险**:
- `/tmp/` 目录权限过于宽松
- 通知文件可能包含项目路径、代码片段
- 未加密敏感信息

**修复建议**:
```typescript
import crypto from 'crypto';

private async sendNotification(info: { commitId: string; files: number; lines: number }): Promise<void> {
  try {
    // 1. 使用更安全的路径
    const notifyDir = path.join(this.config.projectPath, '.ai-notify');
    await fs.promises.mkdir(notifyDir, { mode: 0o700 }); // 仅用户可读写

    // 2. 过滤敏感信息
    const safeMessage = this.sanitizeMessage(message);

    // 3. 加密敏感数据
    const encrypted = this.encryptData({
      message: safeMessage,
      timestamp: new Date().toISOString()
    });

    const notifyFile = path.join(notifyDir, `notify-${Date.now()}.enc`);
    await fs.promises.writeFile(notifyFile, encrypted, { mode: 0o600 });

    // 4. 定期清理（7 天后删除）
    this.scheduleCleanup(notifyFile);
  }
}

private sanitizeMessage(message: string): string {
  // 移除敏感路径、API Key 等
  return message
    .replace(/\/root\/.openclaw\/workspace\/[^\/]+/g, '[PROJECT]')
    .replace(/sk-[a-zA-Z0-9]{32,}/g, '[REDACTED]')
    .replace(/Bearer [^\s]+/g, 'Bearer [REDACTED]');
}

private encryptData(data: any): string {
  const key = process.env.NOTIFICATION_KEY || crypto.randomBytes(32);
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);

  let encrypted = cipher.update(JSON.stringify(data), 'utf8', 'hex');
  encrypted += cipher.final('hex');
  const authTag = cipher.getAuthTag();

  return JSON.stringify({
    data: encrypted,
    iv: iv.toString('hex'),
    authTag: authTag.toString('hex')
  });
}
```

**优先级**: 🔴 P0 - 立即修复  
**预计工作量**: 4 小时

