#### SEC-003: 命令注入风险（高）

**问题代码** (`auto-iteration.ts:408-430`):
```typescript
private async validateCode(): Promise<boolean> {
  try {
    const tscResult = childProcess.execSync('npm run type-check 2>&1', { 
      cwd: frontendPath, 
      encoding: 'utf-8',
      timeout: 120000 
    });
    // ⚠️ execSync 可能受 shell 注入攻击
  }
}
```

**安全风险**:
- `execSync` 使用 `/bin/sh` 执行，可能被注入
- `frontendPath` 未经验证直接传入
- 命令输出可能包含敏感信息

**修复建议**:
```typescript
import { spawn } from 'child_process';
import { promisify } from 'util';

private async validateCode(): Promise<boolean> {
  try {
    const projectPath = this.config.projectPath;
    const frontendPath = path.join(projectPath, 'frontend');

    // 1. 验证路径安全性
    if (!this.isSafePath(frontendPath)) {
      throw new Error('Unsafe frontend path');
    }

    // 2. 使用 spawn 而不是 execSync（避免 shell）
    const result = await this.runCommand('npm', ['run', 'type-check'], {
      cwd: frontendPath,
      timeout: 120000
    });

    // 3. 过滤敏感信息
    const safeOutput = this.sanitizeOutput(result);
    return !safeOutput.includes('error TS');
  }
}

private isSafePath(targetPath: string): boolean {
  const resolved = path.resolve(targetPath);
  const allowedDirs = [
    path.resolve(this.config.projectPath, 'frontend'),
    path.resolve(this.config.projectPath, 'backend')
  ];

  return allowedDirs.some(dir => resolved.startsWith(dir));
}

private async runCommand(
  command: string, 
  args: string[], 
  options: { cwd: string; timeout: number }
): Promise<string> {
  return new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd: options.cwd,
      stdio: ['ignore', 'pipe', 'pipe'],
      timeout: options.timeout
    });

    let stdout = '';
    let stderr = '';

    child.stdout?.on('data', (data) => stdout += data);
    child.stderr?.on('data', (data) => stderr += data);

    child.on('close', (code) => {
      if (code === 0) {
        resolve(stdout + stderr);
      } else {
        reject(new Error(`Command failed: ${stderr || stdout}`));
      }
    });

    child.on('error', reject);
  });
}

private sanitizeOutput(output: string): string {
  return output
    .replace(/\/root\/.openclaw\/workspace\/[^\/]+/g, '[PROJECT]')
    .replace(/sk-[a-zA-Z0-9]{32,}/g, '[REDACTED]');
}
```

