#### 任务 4: 错误处理与重试机制
**工作量**: 2 天

```typescript
// utils/retry-handler.ts
export class RetryHandler {
  async retryWithBackoff<T>(
    fn: () => Promise<T>,
    options: {
      maxRetries?: number;
      initialDelayMs?: number;
      maxDelayMs?: number;
      backoffMultiplier?: number;
      retryableErrors?: string[];
    } = {}
  ): Promise<T> {
    const {
      maxRetries = 3,
      initialDelayMs = 1000,
      maxDelayMs = 30000,
      backoffMultiplier = 2,
      retryableErrors = ['ECONNRESET', 'ETIMEDOUT', 'EAI_AGAIN']
    } = options;

    let lastError: Error;
    let delay = initialDelayMs;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error: any) {
        lastError = error;

        // 检查是否可重试
        if (attempt === maxRetries || !this.isRetryable(error, retryableErrors)) {
          throw error;
        }

        // 指数退避
        logger.warn(`Retrying after ${delay}ms`, { attempt, error: error.message });
        await this.sleep(delay);
        delay = Math.min(delay * backoffMultiplier, maxDelayMs);
      }
    }

    throw lastError!;
  }

  private isRetryable(error: Error, retryableErrors: string[]): boolean {
    return retryableErrors.some(code => error.message.includes(code));
  }

  private sleep(ms: number): Promise<void> {
