// services/metrics-collector.ts
export class MetricsCollector {
  private metrics: Map<string, any[]> = new Map();

  recordAgentExecution(agent: string, duration: number, tokens: number): void {
    this.ensureKey('agent_executions');
    this.metrics.get('agent_executions')!.push({
      agent,
      duration,
      tokens,
      timestamp: new Date()
    });
  }

  recordAPICall(endpoint: string, duration: number, success: boolean): void {
    this.ensureKey('api_calls');
    this.metrics.get('api_calls')!.push({
      endpoint,
      duration,
      success,
      timestamp: new Date()
    });
  }

  getMetrics(): any {
    return {
      agentExecutions: this.metrics.get('agent_executions') || [],
      apiCalls: this.metrics.get('api_calls') || [],
      summary: this.calculateSummary()
    };
  }

  private calculateSummary(): any {
    const executions = this.metrics.get('agent_executions') || [];
    const avgDuration = executions.reduce((sum, e) => sum + e.duration, 0) / executions.length;
    const totalTokens = executions.reduce((sum, e) => sum + e.tokens, 0);

    return {
      avgDuration: Math.round(avgDuration),
      totalTokens,
      totalExecutions: executions.length
    };
  }
}
